  onFileMenu(menu, file) {
    if (file instanceof import_obsidian12.TFile) {
      menu.addItem((item) => {
        item.setTitle("Send to ...").setIcon("paper-plane").onClick(() => {
          new FileShareModal(
            this,
            this.socket,
            this.settings.friends,
            file
          ).open();
        });
      });
    } else if (file instanceof import_obsidian12.TFolder) {
      menu.addItem((item) => {
        item.setTitle("Send folder to ...").setIcon("paper-plane").onClick(() => {
          new FileShareModal(
            this,
            this.socket,
            this.settings.friends,
            null,
            file
          ).open();
        });
      });
    }
  }
  registerFriendCommands() {
    this.friendCommandIds = [];
    this.settings.friends.forEach((friend, index) => {
      if (friend.enableHotkey) {
        const commandId = this.generateHotkeyId(friend.username);
        this.friendCommandIds.push(commandId);
        this.addCommand({
          id: commandId,
          name: `Send current file to ${friend.username}`,
          checkCallback: (checking) => {
            const activeFile = this.app.workspace.getActiveFile();
            if (activeFile) {
              if (!checking) {
                this.sendFileToFriend(activeFile, friend);
              }
              return true;
            }
            return false;
          }
        });
      }
    });
  }
  generateHotkeyId(username) {
    return `send-to-${username.toLowerCase().replace(/[^a-z0-9]/g, "-").replace(/-+/g, "-").replace(/^-|-$/g, "")}`;
  }
  async sendFileToFriend(file, friend) {
    if (this.socket.getWS().readyState !== WebSocket.OPEN) {
      new import_obsidian12.Notice("You are not connected to the FileShare server. Please connect first.");
      return;
    }
    const validation = await this.fileValidator.validateFile(file);
    if (!validation.valid) {
      this.fileValidator.showValidationError(validation.error);
      return;
    }
    this.socket.send("checkOnline", { target: friend.publicKey });
    this.socket.getWS().onmessage = (message) => {
      const data = JSON.parse(message.data);
      if (data.type === "checkOnline" && data.target === friend.publicKey) {
        if (data.online) {
          this.fileRequestQueue.addRequest(file, friend);
          if (this.settings.scanSendingFiles) {
            this.fileTransmitter.scanFileAndSend(file, friend);
          }
        } else {
          new import_obsidian12.Notice(`${friend.username} is offline at the moment`);
        }
      } else if (data.type === "response") {
        this.fileRequestQueue.handleResponse(data.id, data.accepted, data.hash);
      }
    };
  }
